export const FB_QUESTIONS_BY_LANG = {
  ko: FB_QUESTIONS,
  ja: FB_QUESTIONS_JA,
  en: FB_QUESTIONS_EN,
};

// 카테고리 lookup (lang 기준)
export function getCategoriesByLang(lang) {
  return FB_CATEGORIES_BY_LANG[lang] || FB_CATEGORIES_BY_LANG.ko;
}

// 질문 pool lookup (빈 카테고리는 ko로 fallback)
export function getQuestionsByLang(lang) {
  const q = FB_QUESTIONS_BY_LANG[lang];
  if (!q) return FB_QUESTIONS_BY_LANG.ko;
  // 카테고리별로 비어있으면 해당 카테고리만 ko fallback
  const merged = {};
  for (const catId of Object.keys(FB_QUESTIONS)) {
    const arr = q[catId];
    merged[catId] = (arr && arr.length > 0) ? arr : FB_QUESTIONS[catId];
  }
  return merged;
}

// 해당 lang의 시드 보유 여부 (UI에서 "준비 중" 표시 판단용)
export function getLangAvailability() {
  const out = {};
  for (const lang of Object.keys(FB_QUESTIONS_BY_LANG)) {
    const q = FB_QUESTIONS_BY_LANG[lang];
    let total = 0;
    for (const arr of Object.values(q)) total += (arr || []).length;
    out[lang] = total;
  }
  return out;
}

// helper: 빈 답/트롤 → decoys에서 랜덤 채우기 (사용된 텍스트 제외)
export function pickDecoy(question, usedTexts) {
  const decoys = (question.decoys || []).slice();
  for (let i = decoys.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [decoys[i], decoys[j]] = [decoys[j], decoys[i]];
  }
  for (const d of decoys) {
    const norm = normalizeAnswer(d);
    if (!usedTexts.has(norm)) return d;
  }
  return decoys[0] || "(미입력)";
}
